DROP TABLE IF EXISTS `works`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `works` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phaseId` int DEFAULT NULL,
  `dateCreated` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `technique` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dimensions` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `colorPalette` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `emotionalRegister` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `imageUrl` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `imageKey` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `thumbnailUrl` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `journalExcerpt` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `neonReading` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `seriesName` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `isPublished` tinyint(1) NOT NULL DEFAULT '1',
  `sortOrder` int NOT NULL DEFAULT '0',
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `featured` tinyint(1) NOT NULL DEFAULT '0',
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `medium` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `year` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `curatorialHook` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `conceptTags` json DEFAULT NULL,
  PRIMARY KEY (`id`) /*T![clustered_index] CLUSTERED */,
  KEY `works_phaseId_phases_id_fk` (`phaseId`),
  UNIQUE KEY `works_slug_unique` (`slug`),
  CONSTRAINT `works_phaseId_phases_id_fk` FOREIGN KEY (`phaseId`) REFERENCES `phases` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci AUTO_INCREMENT=390001;
