DROP TABLE IF EXISTS `archive_files`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `archive_files` (
  `id` int NOT NULL AUTO_INCREMENT,
  `filename` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `fileType` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fileSize` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fileUrl` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
