INSERT INTO `press_clippings` (`id`, `title`, `source`, `author`, `date`, `excerpt`, `fullText`, `url`, `imageUrl`, `phaseId`, `category`, `isPublished`, `sortOrder`, `createdAt`, `updatedAt`) VALUES (1,'Celestial Secrets: Peter Yuill\'s Sacred Geometry Exhibition','GQ Thailand','Pemika Suyaraj','June 11, 2024','A comprehensive exploration of Peter Yuill\'s installation practice combining light projection, geometric forms, and somatic presence at West Eden Gallery, Bangkok.',NULL,'https://gqthailand.com/culture/art-and-design/article/peter-yuill-celestial-secrets','https://d2xsxph8kpxj0f.cloudfront.net/310519663243139088/ZLCef8c8rdYgPCof2teogL/press/1766831116690-GQ_THAILAND.png',30006,'feature',1,1,'2025-12-27 10:25:27','2025-12-27 10:25:27'),(2,'Circle of Life: Peter Yuill Interview','Tatler Asia','Tara Sobti','May 18, 2020','In-depth artist interview exploring Peter Yuill\'s 20-year career, spiritual philosophy, and geometric practice. Photography by Jocelyn Tam.',NULL,'https://www.tatlerasia.com/the-scene/people-parties/artist-peter-yuill-interview-new-exhibition-alignment','https://d2xsxph8kpxj0f.cloudfront.net/310519663243139088/ZLCef8c8rdYgPCof2teogL/press/1766831127867-tatler_may_2020_peteryuill_1_.jpg',30003,'interview',1,2,'2025-12-27 10:25:54','2025-12-27 10:25:54'),(3,'Inside Peter Yuill\'s Solo Show: Alignment','Prestige Online','Florence Tsai','April 24, 2020','Feature coverage of Peter Yuill\'s \'Alignment\' solo exhibition, with focus on artist\'s workspace, practice methodology, and philosophical approach.',NULL,'https://www.prestigeonline.com/hk/lifestyle/art-plus-design/inside-peter-yuills-solo-show-alignment/',NULL,30003,'feature',1,3,'2025-12-27 10:25:54','2025-12-27 10:25:54');
